const config = $input.first()?.json || {};
const rawSourcesJson = (config.rssSourcesJson || '').trim();
const fallbackSources = [
  {
    feedUrl: 'http://rsshub:1200/xiaoyuzhou/podcast/648b0b641c48983391a63f98',
    sourceName: '42章经',
    sourceType: 'podcast'
  }
];

let sources = fallbackSources;
if (rawSourcesJson) {
  try {
    const parsed = JSON.parse(rawSourcesJson);
    if (!Array.isArray(parsed)) {
      throw new Error('RSS_SOURCE_URLS_JSON must be a JSON array');
    }
    sources = parsed;
  } catch (error) {
    throw new Error(`RSS_SOURCE_URLS_JSON parse failed: ${error.message}`);
  }
}

const obsidianInboxDir = (config.obsidianInboxDir || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor';

return sources.map((source, index) => {
  const feedUrl = (source.feedUrl || source.url || '').trim();
  if (!feedUrl) {
    throw new Error(`Source ${index + 1} is missing feedUrl/url`);
  }

  return {
    json: {
      feedUrl,
      sourceName: source.sourceName || source.name || `source-${index + 1}`,
      sourceType: source.sourceType || 'rss',
      obsidianInboxDir
    }
  };
});

const sourceContext = (() => {
  try {
    return $('Feed Sources').item.json || {};
  } catch {
    return {};
  }
})();

const rawHtml = [
  $json['content:encoded'],
  $json.content,
  $json.contentSnippet,
  $json.summary,
  $json.description
].find((value) => typeof value === 'string' && value.trim()) || '';

return {
  json: {
    source_type: (sourceContext.sourceType || 'rss').trim() || 'rss',
    source_name: (sourceContext.sourceName || sourceContext.name || '').trim(),
    canonical_url: String($json.link || $json.guid || '').trim(),
    original_id: String($json.guid || $json.id || $json.link || '').trim(),
    title: (($json.title || '').trim() || 'untitled'),
    author: (($json.creator || $json.author || '').trim()),
    published_at: $json.isoDate || $json.pubDate || new Date().toISOString(),
    media_type: 'text',
    raw_html: rawHtml,
    raw_text: '',
    obsidian_inbox_dir: sourceContext.obsidianInboxDir || $json.obsidianInboxDir || '00_Inbox/AI_Information_Processor',
    extra_tags: ['raw-ingest'],
    upstream_task_id: '',
    upstream_view_token: '',
    upstream_summary: '',
    original_item: $json
  }
};

const slugify = (value = '') => String(value)
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9\u4e00-\u9fa5]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .toLowerCase();

const yamlEscape = (value = '') => String(value)
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"');

const yamlBlock = (key, value = '') => {
  const normalized = String(value || '').replace(/\r\n/g, '\n').trim();
  if (!normalized) {
    return '';
  }
  const indented = normalized
    .split('\n')
    .map((line) => `  ${line}`)
    .join('\n');
  return `${key}: |-\n${indented}\n`;
};

const inboxDir = ($json.obsidianInboxDir || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor';
const dateForFile = new Date($json.published_at || Date.now());
const yyyy = dateForFile.getFullYear();
const mm = String(dateForFile.getMonth() + 1).padStart(2, '0');
const dd = String(dateForFile.getDate()).padStart(2, '0');
const datePrefix = `${yyyy}-${mm}-${dd}`;
const sourceType = slugify($json.source_type || 'rss') || 'rss';
const itemIdShort = String($json.item_id || 'unknown').slice(0, 10);
const titleSlug = slugify($json.title).slice(0, 80) || 'untitled';
const fileBaseName = `${datePrefix}_${sourceType}_${itemIdShort}_${titleSlug}`;
const relativeFilePath = `${inboxDir}/${fileBaseName}.md`;
const summary = String($json.summary || '').trim();
const reason = String($json.reason || '').trim();
const excerpt = (summary || ($json.content_text || '').slice(0, 280)).trim();
const dedupeAction = String($json.dedupe_action || 'full_push').trim() || 'full_push';
const notificationMode = String($json.notification_mode || '').trim();
const matchedPayload = $json.matched_payload && typeof $json.matched_payload === 'object' ? $json.matched_payload : null;
const matchedScore = Number($json.matched_score || 0);
const matchedTitle = matchedPayload ? String(matchedPayload.title || '').trim() : '';
const matchedItemId = matchedPayload ? String(matchedPayload.item_id || '').trim() : '';
const matchedCanonicalUrl = matchedPayload ? String(matchedPayload.canonical_url || '').trim() : '';
const tags = Array.isArray($json.tags) && $json.tags.length
  ? $json.tags.filter(Boolean)
  : ['inbox', 'ai-information-processor'];
const normalizedTags = [...new Set([...tags, `dedupe-${dedupeAction}`].filter(Boolean))];
const tagLines = normalizedTags.map((tag) => `  - ${tag}`).join('\n');
const authorLine = $json.author ? `author: \"${yamlEscape($json.author)}\"\n` : '';
const originalIdLine = $json.original_id ? `original_id: \"${yamlEscape($json.original_id)}\"\n` : '';
const sourceHostLine = $json.source_host ? `source_host: \"${yamlEscape($json.source_host)}\"\n` : '';
const enrichedAtLine = $json.enriched_at ? `enriched_at: \"${yamlEscape($json.enriched_at)}\"\n` : '';
const notificationModeLine = notificationMode ? `notification_mode: \"${yamlEscape(notificationMode)}\"\n` : '';
const matchedScoreLine = Number.isFinite(matchedScore) && matchedScore > 0 ? `matched_score: ${matchedScore}\n` : '';
const matchedItemIdLine = matchedItemId ? `matched_item_id: \"${yamlEscape(matchedItemId)}\"\n` : '';
const matchedCanonicalUrlLine = matchedCanonicalUrl ? `matched_canonical_url: \"${yamlEscape(matchedCanonicalUrl)}\"\n` : '';
const matchedSameItemLine = $json.matched_same_item ? 'matched_same_item: true\n' : '';
const summaryLine = yamlBlock('summary', summary);
const reasonLine = yamlBlock('reason', reason);
const summarySection = summary ? `## Summary\n\n${summary}\n\n` : '';
const reasonSection = reason ? `## Reason\n\n${reason}\n\n` : '';
const dedupeLines = matchedPayload ? [
  `- Action: ${dedupeAction}`,
  `- Notification Mode: ${notificationMode || 'n/a'}`,
  Number.isFinite(matchedScore) && matchedScore > 0 ? `- Matched Score: ${matchedScore.toFixed(4)}` : '',
  matchedItemId ? `- Matched Item ID: ${matchedItemId}` : '',
  matchedTitle ? `- Matched Title: ${matchedTitle}` : '',
  matchedCanonicalUrl ? `- Matched Canonical URL: ${matchedCanonicalUrl}` : '',
  $json.matched_same_item ? '- Same Item ID Match: true' : ''
].filter(Boolean).join('\n') : '';
const dedupeSection = dedupeLines ? `## Dedupe Context\n\n${dedupeLines}\n\n` : '';
const canonicalUrl = $json.canonical_url || '';
const workflowName = $json.enriched_at ? 'rss-to-obsidian-mainline-qdrant' : 'rss-to-obsidian-raw';
const markdown = `---\ntitle: \"${yamlEscape($json.title)}\"\nitem_id: \"${yamlEscape($json.item_id)}\"\nsource_type: \"${yamlEscape($json.source_type)}\"\nsource_name: \"${yamlEscape($json.source_name)}\"\n${sourceHostLine}${originalIdLine}canonical_url: \"${yamlEscape(canonicalUrl)}\"\npublished_at: \"${yamlEscape($json.published_at)}\"\ningested_at: \"${yamlEscape($json.ingested_at)}\"\n${enrichedAtLine}media_type: \"${yamlEscape($json.media_type)}\"\ncontent_hash: \"${yamlEscape($json.content_hash)}\"\nworkflow: \"${workflowName}\"\nscore: ${Number($json.score || 0)}\ncategory: \"${yamlEscape($json.category || 'pending')}\"\ndedupe_action: \"${yamlEscape(dedupeAction)}\"\nstatus: \"${yamlEscape($json.status || 'raw')}\"\n${notificationModeLine}${matchedScoreLine}${matchedItemIdLine}${matchedCanonicalUrlLine}${matchedSameItemLine}${authorLine}${summaryLine}${reasonLine}tags:\n${tagLines}\n---\n\n# ${$json.title}\n\n> Source Name: ${$json.source_name || 'unknown-source'}\n> Canonical URL: ${canonicalUrl || 'N/A'}\n\n## Excerpt\n\n${excerpt || 'No text excerpt extracted.'}\n\n${summarySection}${reasonSection}${dedupeSection}## Raw Content\n\n${$json.content_text || 'No text content extracted from this feed item.'}\n`;

return {
  json: {
    ...$json,
    fileBaseName,
    relativeFilePath,
    vault_path: relativeFilePath,
    vault_write: 'written'
  },
  binary: {
    data: {
      data: Buffer.from(markdown, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: `${fileBaseName}.md`,
      fileExtension: 'md'
    }
  }
};
